def col(name: str) -> Expr:
    """Create a column reference expression."""
    return Expr("col", name)

def lit(value: Any) -> Expr:
    """Create a literal value expression."""
    return Expr("lit", value)

def when(condition: 'Expr', then: Any, otherwise: Any = 0) -> 'Expr':
    """CASE WHEN condition THEN then ELSE otherwise END."""
    if not isinstance(then, Expr):      then      = lit(then)
    if not isinstance(otherwise, Expr): otherwise = lit(otherwise)
    return Expr("case_when", condition, then, otherwise)

def row_number() -> 'Expr':
    """Create a row-number expression (1-based, no input column needed).

    Use with ``.over()`` to get row numbers within a partition::

        row_number().over("region", order_by="date").alias("rn")

    Without ``.over()``, numbers the whole table sequentially.
    """
    return Expr("row_number")
